namespace sv_533ee073719642c4b5dd44a910fc711c.Services;

public class WarehouseInfo
{
    public static readonly IReadOnlyList<WarehouseInfo> All =
    [
        new("wh-1", "Warehouse A — East"),
        new("wh-2", "Warehouse B — West"),
        new("wh-3", "Warehouse C — Central"),
    ];

    public string Id { get; }
    public string Name { get; }

    public WarehouseInfo(string id, string name)
    {
        Id = id;
        Name = name;
    }
}

namespace sv_533ee073719642c4b5dd44a910fc711c.Services;

public class InventoryAlertService
{
    private readonly Random _random = new();

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        // Simulate a database query with a short delay.
        var count = _random.Next(0, 16);
        return Task.FromResult(count);
    }
}

namespace sv_533ee073719642c4b5dd44a910fc711c.Services;

/// <summary>
/// Scoped service that holds the current low-stock alert count and notifies
/// subscribers when it changes. Per-circuit on Blazor Server, so each user
