arguments.file_text:
@page "/dashboard"
@rendermode InteractiveServer
@inject sv_533ee073719642c4b5dd44a910fc711c.Services.InventoryAlertService AlertService
@inject sv_533ee073719642c4b5dd44a910fc711c.Services.AlertState AlertState
@implements IAsyncDisposable

<PageTitle>Warehouse Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

@if (Warehouse is not null)
{
    <h4 class="text-muted mb-4">@Warehouse.Name</h4>

    <div class="row g-4">
        <div class="col-md-4">
            <div class="card @(AlertState.LowStockCount > 0 ? "border-danger" : "border-success")">
                <div class="card-body text-center">
                    <h5 class="card-title">Low-Stock Alerts</h5>
                    <p class="display-4 @(AlertState.LowStockCount > 0 ? "text-danger" : "text-success")">
                        @AlertState.LowStockCount
                    </p>
                    <p class="text-muted">items below minimum level</p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body text-center">
                    <h5 class="card-title">Site ID</h5>
                    <p class="display-6">@Warehouse.Id</p>
                </div>
            </div>
        </div>

        <div class="col-md-4">
            <div class="card">
                <div class="card-body text-center">
                    <h5 class="card-title">Polling</h5>
                    <p class="display-6">@(_isPolling ? "Active" : "Stopped")</p>
                    <p class="text-muted">every 10 seconds</p>
                </div>
            </div>
        </div>
    </div>
}
else
{
    <p>No warehouse selected.</p>
}

@code {
    [CascadingParameter]
    private sv_533ee073719642c4b5dd44a910fc711c.Services.WarehouseInfo? Warehouse { get; set; }

    private CancellationTokenSource _cts = new();
    private bool _isPolling;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        // Subscribe to AlertState so the dashboard re-renders when the
        // sidebar badge triggers a change (or vice-versa).
        _alertHandler = () => InvokeAsync(StateHasChanged);
        AlertState.OnChange += _alertHandler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the cascading warehouse changes.
        await StopPollingAsync();
        _cts = new CancellationTokenSource();

        if (Warehouse is not null)
        {
            await PollOnceAsync();
            _ = PollLoopAsync(_cts.Token);
        }
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        _isPolling = true;
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await PollOnceAsync();
            }
        }
        catch (OperationCanceledException)
        {
            // Expected when leaving the page or switching warehouse.
        }

        _isPolling = false;
    }

    private async Task PollOnceAsync()
    {
        if (Warehouse is null) return;

        var count = await AlertService.GetLowStockCountAsync(Warehouse.Id);
        AlertState.SetLowStockCount(count);
        await InvokeAsync(StateHasChanged);
    }

    private async Task StopPollingAsync()
    {
        await _cts.CancelAsync();
        _cts.Dispose();
        _isPolling = false;
    }

    public async ValueTask DisposeAsync()
    {
        AlertState.OnChange -= _alertHandler;
        await StopPollingAsync();
    }
}

